import java.io.*;

public class SecureCommandInjectionExample {
    public static void main(String[] args) throws IOException {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));

        System.out.print("Enter a command to execute: ");
        String command = br.readLine();

        // Sanitize the input to prevent Command Injection
        String sanitizedCommand = sanitizeCommand(command);

        // Execute the sanitized command using ProcessBuilder
        Process process = new ProcessBuilder(sanitizedCommand.split("\\s+")).start();

        BufferedReader reader = new BufferedReader(new InputStreamReader(process.getInputStream()));
        String line;

        while ((line = reader.readLine()) != null) {
            System.out.println(line);
        }
    }

    // Method to sanitize the user input by escaping special characters
    private static String sanitizeCommand(String command) {
        return command.replaceAll("[^A-Za-z0-9]", "");
    }
}

